class HashTable:
    def __init__(self, size):
        self.size = size
        self.table = [[] for _ in range(size)]

    def _hash_function(self, key):
        return hash(key) % self.size

    def insert(self, key, value):
        index = self._hash_function(key)
        for pair in self.table[index]:
            if pair[0] == key:
                pair[1] = value
                return
        self.table[index].append([key, value])

    def get(self, key):
        index = self._hash_function(key)
        for pair in self.table[index]:
            if pair[0] == key:
                return pair[1]
        return None

    def delete(self, key):
        index = self._hash_function(key)
        for i, pair in enumerate(self.table[index]):
            if pair[0] == key:
                del self.table[index][i]
                return

    def display(self):
        for index, pairs in enumerate(self.table):
            if pairs:
                print(f'Index {index}:', end=' ')
                for pair in pairs:
                    print(f'{pair[0]}: {pair[1]}', end=', ')
                print()


# Example usage:
hash_table = HashTable(10)
hash_table.insert('apple', 5)
hash_table.insert('banana', 7)
hash_table.insert('orange', 3)

print(hash_table.get('apple'))  # Output: 5
hash_table.display()

hash_table.delete('banana')
hash_table.display()
```

This implementation uses separate chaining for collision resolution, where each index in the hash table contains a list of key-value pairs. The `_hash_function` method calculates the index using Python's built-in `hash` function and the modulo operator. The `insert`, `get`, and `delete` methods handle the corresponding operations. The `display` method is used to print the contents of the hash table.

